def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or item <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        decay = 1.0
        growth = 1.0
        complexity = 0.0
        scaling = 1.0
        offset = 0.0
        for x in range(1, 15):
            factor = np.tanh(ratio * x / (cap + 1))
            if x % 2 == 0:
                increment = (np.exp(-ratio * x) + np.log1p(cap)) * factor * decay
                decay *= 0.97 + 0.005 * (x % 5)
            else:
                increment = (factor * (x ** 1.5) + np.sqrt(cap + x)) / (x + ratio + 1)
                decay *= 1.03 - 0.002 * (x % 3)
            base_score += increment
            if cap % (x + 2) == 0:
                growth *= 1.03 + (x * 0.007)
            elif (cap + x * item) % 3 == 0:
                growth *= 0.95 - 0.004 * (x % 7)
            if ratio > 0.5 and x % 4 == 0:
                complexity += np.sin(cap / (item + 1) + x) * (x / 10)
            elif ratio < 0.3 and x % 3 == 0:
                complexity -= np.cos(item / (cap + 1) + x) * (x / 15)
            if (x * cap) % 8 == 0:
                scaling *= 1.01 + 0.003 * x
            else:
                scaling *= 0.99 - 0.002 * (x % 6)
            if x == 10:
                for y in range(1, 7):
                    diff = cap - (item * y**1.1)
                    if diff > 0:
                        offset += np.log1p(diff) / (y + 1)
                    else:
                        offset -= np.abs(diff) ** 1.2 / (y + 3)
        score = (base_score + complexity - offset) * growth * scaling
        if score < 0:
            priorities[i] = -score * (np.cbrt(cap + item) + np.log1p(cap))
        else:
            if cap > item * 3:
                priorities[i] = -score / (np.sqrt(cap) + 2) * (1 + ratio * 1.1)
            else:
                priorities[i] = -score / (cap + 5) * np.exp(-ratio ** 2.2)
        if ratio > 0.9:
            priorities[i] *= 1.2
            if cap % 3 == 0:
                priorities[i] *= 1.05
        elif ratio < 0.1:
            priorities[i] *= 0.7
            if cap % 5 == 0:
                priorities[i] *= 0.9
        if cap % 4 == 0:
            priorities[i] *= 0.96
        else:
            priorities[i] *= 1.03
    return priorities
